const headers = $('Ingest Webhook').first().json.headers || {};
const authHeader = headers.authorization || headers.Authorization || '';
const token = authHeader.replace(/^Bearer\s+/i, '').trim();
const expectedToken = 'ObruI6NrfgChsBl1HUHvZvQs8v9EiFcJ1Zsxez205_s';
if (expectedToken && token !== expectedToken) {
  throw new Error('401 Unauthorized: invalid Bearer token');
}

const body = $('Ingest Webhook').first().json.body || $('Ingest Webhook').first().json;
const chatId = parseInt(body.chat_id || '0') || 0;
const filename = (body.filename || 'upload.bin').replace(/[^a-zA-Z0-9._-]/g, '_');
const mime = body.mime || 'application/octet-stream';

const allBinary = $('Ingest Webhook').first().binary || {};
const fileKey = Object.keys(allBinary)[0];
const binary = fileKey ? allBinary[fileKey] : null;
if (!binary) throw new Error('No file received — send multipart/form-data with a file field');
const buf = Buffer.from(binary.data, 'base64');
const sha256 = sha256hex(buf);

// Extract text here — keeps binary OUT of downstream execution context
const isText = mime.includes('text') || filename.endsWith('.txt') || filename.endsWith('.md');
const isPdf = mime.includes('pdf') || filename.toLowerCase().endsWith('.pdf');
const isDocx = mime.includes('docx') || mime.includes('word') || filename.toLowerCase().endsWith('.docx');

let rawText = '';
if (isText) {
  rawText = buf.toString('utf8').trim();
} else if (isPdf) {
  const pdfParse = require('pdf-parse');
  const data = await pdfParse(buf);
  rawText = data.text.trim();
} else if (isDocx) {
  const mammoth = require('mammoth');
  const result = await mammoth.extractRawText({ buffer: buf });
  rawText = result.value.trim();
} else {
  rawText = buf.toString('utf8').trim();
}

if (!rawText) throw new Error('No text extracted from document');

// Output rawText in JSON — NO binary field — keeps downstream runner context small
return [{ json: {
  chat_id: chatId,
  filename,
  mime,
  sha256,
  fileSize: buf.length,
  startMs: Date.now(),
  rawText
}}];

const item = items[0].json;
const rawText = String(item.rawText || '').trim();
const doc_id = item.doc_id || '';
if (!rawText) throw new Error('No rawText in merged input');
if (!doc_id) throw new Error('No doc_id in merged input');

const meta = { doc_id, chat_id: item.chat_id || 0, sha256: item.sha256 || '', filename: item.filename || '', startMs: item.startMs || 0 };

const CHUNK_SIZE = 512; const OVERLAP = 50;
const chunks = []; let start = 0;
while (start < rawText.length) {
  const end = Math.min(start + CHUNK_SIZE, rawText.length);
  const chunkText = rawText.slice(start, end).trim();
  if (chunkText.length > 20) {
    chunks.push({ json: { ...meta, section: '', text: chunkText, chunk_idx: chunks.length, totalChunks: 0 } });
  }
  if (end >= rawText.length) break;
  start = Math.max(end - OVERLAP, 0);
  if (start >= end) break;
}
for (const c of chunks) { c.json.totalChunks = chunks.length; }
if (!chunks.length) throw new Error('No chunks extracted from rawText');
return chunks;

